			&lt;li&gt;&lt;strong&gt;राजेंद्र विलास &lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;महल&lt;/span&gt;&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;जगमोहन &lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;महल&lt;/span&gt;&lt;/li&gt;
